import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-12cbd7d3.js";const p={},e=t(`<p>클로저는 난해하기로 유명한 자바스크립트 개념 중 하나다. 클로저는 자바스크립트의 고유의 개념이 아니다.<br> 함수를 일급 객체로 취급하는 함수형 프로그래밍 언어(하스켈, 리스트, 얼랭, 스칼라 등)에서 사용되는 중요한 특성이다.</p><p>MDN에서는 클로저에 대해 다음과 같이 정의하고 있다.</p><div class="hint-container info"><p class="hint-container-title">Info</p><p>클로저는 함수와 그 함수가 선언된 렉시컬 환경의 조합이다.</p></div><p>위 정의에서 먼저 이해해야할 핵심 키워드는 &quot;함수가 선언된 렉시컬 환경&quot;이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">outerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

  <span class="token keyword">function</span> <span class="token function">innerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 10</span>
  <span class="token punctuation">}</span>

  <span class="token function">innerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">outerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>중첩 함수 <code>innerFunc</code>의 상위 스코프는 외부 함수 <code>outerFunc</code>의 스코프다.<br> 따라서 <code>innerFunc</code> 내부에서 자신을 포함하고 있는 외부 함수 <code>outerFunc</code>의 x 변수에 접근할 수 있다.<br> 만약 <code>innerFunc</code> 함수가 <code>outerFunc</code> 함수의 내부에서 정의된 중첩 함수가 아니라면 <code>innerFunc</code> 함수를 <code>outerFunc</code> 함수의 내부에서 호출한다 하더라도 <code>outerFunc</code> 함수의 변수에 접근할 수 없다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">outerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
  <span class="token function">innerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">innerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
<span class="token punctuation">}</span>

<span class="token function">outerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>이 같은 현상이 발생하는 이유는 자바스크립트가 렉시컬 스코프를 따르는 프로그래밍 언어이기 때문이다.</p><h2 id="_1-렉시컬-스코프" tabindex="-1"><a class="header-anchor" href="#_1-렉시컬-스코프" aria-hidden="true">#</a> 1. 렉시컬 스코프</h2><p>자바스크립트 엔진은 함수를 어디서 호출했는지가 아니라 함수를 어디 정의했는지에 따라 상위 스코프를 결정한다.<br> 이를 렉시컬 스코프(정적 스코프)라 한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
  <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ?</span>
<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ?</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제는 foo 함수와 bar 함수는 모두 전역에서 정의된 전역 함수다.<br> 함수의 상위 스코프는 함수를 어디서 정의했느냐에 따라 결정되고 foo 함수와 bar 함수의 상위 스코프는 전역이다.<br> 함수를 어디서 호출하는지는 함수의 상위 스코프 결정에 어떠한 영향도 주지 못한다.<br> 즉, 함수의 상위 스코프는 함수를 정의한 위치에 의해 정적으로 결정되고 변하지 않는다.</p><p>렉시컬 환경의 &quot;외부 렉시컬 환경에 대한 참조&quot;에 저장할 참조값, 즉 상위 스코프에 대한 참조는 함수 정의가 평가되는 시점에 함수가 정의된 환경(위치)에 의해 결정된다. 이것이 바로 렉시컬 스코프다.</p><h2 id="_2-함수-객체의-내부-슬롯-environment" tabindex="-1"><a class="header-anchor" href="#_2-함수-객체의-내부-슬롯-environment" aria-hidden="true">#</a> 2. 함수 객체의 내부 슬롯 <code>[[Environment]]</code></h2><p>함수가 정의된 환경(위치)과 호출되는 환경(위치)은 다를 수 있다.<br> 따라서 렉시컬 스코프가 가능하려면 함수는 자신이 호출되는 환경과는 상관없이 자신이 정의된 환경,<br> 즉 상위 스코프를 기억해야한다. 이를 위해 함수는 자신의 내부 슬롯 <code>[[Environment]]</code>에 자신이 정의된 환경<br> 즉 상위 스코프의 참조를 저장한다.</p><p>함수 객체의 내부 슬롯 <code>[[Environment]]</code>에 저장된 현재 실행 중인 실행 컨텍스트의 렉시컬 환경의 참조가 바로 상위 스코프다. 또한 자신이 호출되었을 때 생성될 함수 렉시컬 환경의 &quot;외부 렉시컬 환경에 대한 참조&quot;에 저장될 참조값이다. 함수 객체는 내부 슬롯 <code>[[Environment]]</code>에 저장된 렉시컬 환경의 참조, 즉 상위 스코프를 자신이 존재하는 한 기억한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

  <span class="token comment">// 상위 스코프는 함수 정의 환경(위치)에 따라 결정된다.</span>
  <span class="token comment">// 함수 호출 위치와 상위 스코프는 아무런 관계가 없다.</span>
  <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 함수 bar는 자신의 상위 스코프, 즉 전역 렉시컬 환경을 [[Environment]]에 저장하여 기억한다.</span>
<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ?</span>
<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ?</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제의 foo 함수 내부에서 bar 함수가 호출되어 실행 중인 시점의 실행 컨텍스트는 다음과 같다.</p><figure><img src="" alt="그림 24-1. 함수 객체의 내부 슬롯 에는 상위 스코프가 저장" tabindex="0" loading="lazy"><figcaption>그림 24-1. 함수 객체의 내부 슬롯 <code>[[Environment]]</code>에는 상위 스코프가 저장</figcaption></figure><p>foo 함수와 bar 함수는 모두 전역에서 함수 선언문으로 정의되었다.<br> foo 함수와 bar 함수는 모두 전역 코드가 평가되는 시점에 평가되어 함수 객체를 생성하고 전역 객체 window의 메서드가 된다.</p><p>함수 코드 평가는 아래 순서로 진행된다.</p><ol><li>함수 실행 컨텍스트 생성</li><li>함수 렉시컬 환경 생성<br> 2.1. 함수 환경 레코드 생성<br> 2.2. this 바인딩<br> 2.3. 외부 렉시컬 환경에 대한 참조 결정</li></ol><h2 id="_3-클로저와-렉시컬-환경" tabindex="-1"><a class="header-anchor" href="#_3-클로저와-렉시컬-환경" aria-hidden="true">#</a> 3. 클로저와 렉시컬 환경</h2><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token comment">// ①</span>
<span class="token keyword">function</span> <span class="token function">outer</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
  <span class="token keyword">const</span> <span class="token function-variable function">inner</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token comment">// ②</span>
  <span class="token keyword">return</span> inner<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// outer 함수를 호출하면 중첩 함수 inner를 반환한다.</span>
<span class="token comment">// 그리고 outer 함수의 실행 컨텍스트는 실행 컨텍스트 스택에서 팝되어 제거된다.</span>
<span class="token keyword">const</span> innerFunc <span class="token operator">=</span> <span class="token function">outer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ③</span>
<span class="token function">innerFunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ④ 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>③의 outer 함수를 호출하면 outer 함수는 중첩 함수 inner를 반환하고 생명 주기를 마감<br> ④에서 실행 결과 outer 함수의 지역 변수 x의 값인 10이다. 이미 생명 주기가 종료되어 실행 컨텍스트 스택에서 제거된 outer 함수의 지역 변수 x가 다시 부활이라도 한 듯이 동작</p><p>이처럼 외부 함수보다 중첩 함수가 더 오래 유지되는 경우 중첩 함수는 이미 생명 주기가 종료된 외부 함수의 변수를 참. 이러한 중첩 함수를 클로저라고 부른다.</p><p>① 위 예제에서 outer 함수가 평가되어 함수 객체를 생성할 때 현재 실행 중인 실행 컨텍스트의 렉시컬 환경, 즉 전역 렉시컬 환경을 outer 함수 객체의 <code>[[Environment]]</code> 내부 슬롯에 상위 스코프로서 저장.</p><figure><img src="" alt="그림 24-2. 전역 함수 객체의 상위 스코프 결정" tabindex="0" loading="lazy"><figcaption>그림 24-2. 전역 함수 객체의 상위 스코프 결정</figcaption></figure><p>outer 함수를 호출하면 outer 함수의 렉시컬 환경이 생성되고 앞서 outer 함수 객체의 <code>[[Environment]]</code> 내부 슬롯에 저장된 전역 렉시컬 환경을 outer 함수 렉시컬 환경의 외부 렉시컬 환경에 대한 참조에 할당한다.</p><p>중첩 함수 inner는 자신의 <code>[[Environment]]</code>내부 슬롯에 현재 실행 중인 실행 컨텍스트의 렉시컬 환경,<br> 즉 outer 함수의 렉시컬 환경을 상위 스코프로서 저장한다.</p><figure><img src="" alt="그림 24-3. 중첩 함수의 상위 스코프 결정" tabindex="0" loading="lazy"><figcaption>그림 24-3. 중첩 함수의 상위 스코프 결정</figcaption></figure><p>outer 함수의 실행 컨텍스트는 실행 컨텍스트 스택에서 제거되지만 outer 함수의 렉시컬 환경까지 소멸하는 것은 아니다.</p><p>inner 함수는 전역 변수 innerFunc에 의해 참조되고 있으므로 가비지 컬렉션의 대산ㅇ이 되지 않기 때문이다.<br> 가비지 컬렉터는 누군가가 참조하고 있는 메모리 공간을 함부로 해제하지 않는다.</p><figure><img src="" alt="그림 24-4. outer 함수의 실행 컨텍스트가 제거되어도 outer 함수의 렉시컬 환경은 유지" tabindex="0" loading="lazy"><figcaption>그림 24-4. outer 함수의 실행 컨텍스트가 제거되어도 outer 함수의 렉시컬 환경은 유지</figcaption></figure><p>outer 함수가 반환한 inner 함수를 호출하면 inner 함수의 실행 컨텍스트가 생성되고 실행 컨텍스트 스택에 푸시된다. 그리고 렉시컬 환경의 외부 렉시컬 환경에 대한 참조에는 inner 함수 객체의 <code>[[Environment]]</code> 내부 슬롯에 저장되어 있는 참조값이 할당</p><figure><img src="" alt="그림 24-5. 외부 함수가 소멸해도 반환된 중첩 함수는 외부 함수의 변수에 참조" tabindex="0" loading="lazy"><figcaption>그림 24-5. 외부 함수가 소멸해도 반환된 중첩 함수는 외부 함수의 변수에 참조</figcaption></figure><p>중첩 함수 inner는 외부 함수 outer보다 더 오래 생존했다.<br> 자바스크립트의 모든 함수는 상위 스코프를 기억하므로 이론적으로 모든 함수는 클로저다.<br> 하지만 일반적으로 모든 함수를 클로저라고 하지 않는다.</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token doctype"><span class="token punctuation">&lt;!</span><span class="token doctype-tag">DOCTYPE</span> <span class="token name">html</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
    <span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
      <span class="token keyword">const</span> y <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>

      <span class="token comment">// 일반적으로 클로저라고 하지 않는다.</span>
      <span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">const</span> z <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span>

        <span class="token keyword">debugger</span><span class="token punctuation">;</span>
        <span class="token comment">// 상위 스코프의 식별자를 참조하지 않는다.</span>
        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>z<span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token punctuation">}</span>

      <span class="token keyword">return</span> bar<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">const</span> bar <span class="token operator">=</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  </span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="" alt="그림 24-6. 상위 스코프의 어떤 식별자도 참조하지 않는 함수는 클로저가 아니다." tabindex="0" loading="lazy"><figcaption>그림 24-6. 상위 스코프의 어떤 식별자도 참조하지 않는 함수는 클로저가 아니다.</figcaption></figure><p>위 예제의 중첩 함수 bar는 외부 함수 foo보다 더 오래 유지되지만 상위 스코프의 어떤 식별자도 참조하지 않는다.<br> 참조하지도 않는 식별자를 기억하는 것은 메모리 낭비이기 때문에 bar 함수는 클로저라고 할 수 없다.</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token doctype"><span class="token punctuation">&lt;!</span><span class="token doctype-tag">DOCTYPE</span> <span class="token name">html</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
    <span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">const</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

      <span class="token comment">// 일반적으로 클로저라고 하지 않는다.</span>
      <span class="token comment">// bar 함수는 클로저였지만 곧바로 소멸한다.</span>
      <span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">debugger</span><span class="token punctuation">;</span>
        <span class="token comment">// 상위 스코프의 식별자를 참조한다.</span>
        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token punctuation">}</span>
      <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  </span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="" alt="그림 24-7. 중첩 함수 bar는 클로저였지만 외부 함수보다 일찍 소멸되기 떄문에 클로저의 본질에 부합하지 않는다." tabindex="0" loading="lazy"><figcaption>그림 24-7. 중첩 함수 bar는 클로저였지만 외부 함수보다 일찍 소멸되기 떄문에 클로저의 본질에 부합하지 않는다.</figcaption></figure><p>위 예제의 중첩 함수 bar는 상위 스코프의 식별자를 참조하고 있으므로 클로저다.<br> 하지만 외부 함수 foo의 외부로 중첩 함수 bar가 반환되지 않는다.</p><h2 id="_4-클로저의-활용" tabindex="-1"><a class="header-anchor" href="#_4-클로저의-활용" aria-hidden="true">#</a> 4. 클로저의 활용</h2><h2 id="_5-캡슐화와-정보-은닉" tabindex="-1"><a class="header-anchor" href="#_5-캡슐화와-정보-은닉" aria-hidden="true">#</a> 5. 캡슐화와 정보 은닉</h2><h2 id="_6-자주-발생하는-실수" tabindex="-1"><a class="header-anchor" href="#_6-자주-발생하는-실수" aria-hidden="true">#</a> 6. 자주 발생하는 실수</h2>`,46),c=[e];function o(i,l){return s(),a("div",null,c)}const d=n(p,[["render",o],["__file","deepdive24.html.vue"]]);export{d as default};
